tasklist("recipe", "Generates a complete recipe with ingredients, technique guidance, and nutritional breakdown", [
  {
    "id": "select-cuisine-and-dish",
    "instructions": "Based on the user's request and knowledge context (cuisine type, dietary restrictions, preferred cooking techniques), determine the appropriate cuisine and recommend a specific dish. Consider the occasion, number of servings, available time, and dietary needs. Load the relevant cuisine knowledge to inform the recommendation. Suggest a dish that matches the user's skill level and available equipment.",
    "outputSchema": {
      "cuisineType": {
        "type": "string",
        "description": "Selected cuisine (e.g., 'Italian', 'Japanese', 'Mexican')"
      },
      "dishName": {
        "type": "string",
        "description": "Specific dish name"
      },
      "description": {
        "type": "string",
        "description": "Brief description of the dish and its origin"
      },
      "servings": {
        "type": "number",
        "description": "Number of servings"
      },
      "estimatedTime": {
        "type": "string",
        "description": "Total estimated cooking time (e.g., '45 minutes', '1h 30min')"
      },
      "difficulty": {
        "type": "string",
        "enum": [
          "beginner",
          "intermediate",
          "advanced"
        ],
        "description": "Skill level required"
      },
      "rationale": {
        "type": "string",
        "description": "Why this dish fits the user's context and preferences"
      }
    }
  },
  {
    "id": "gather-ingredients",
    "instructions": "Based on the selected dish, generate a complete ingredient list organized by category. Include precise quantities for the specified number of servings. For each ingredient that may conflict with dietary restrictions, provide a substitution. Flag any allergens. Use the scaleIngredients function if the user needs to adjust servings. Consider seasonal availability and suggest alternatives for hard-to-find items.",
    "outputSchema": {
      "categories": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "name": {
              "type": "string",
              "description": "Category name (e.g., 'Proteins', 'Vegetables', 'Pantry Staples')"
            },
            "items": {
              "type": "array",
              "items": {
                "type": "object",
                "properties": {
                  "ingredient": {
                    "type": "string"
                  },
                  "quantity": {
                    "type": "string"
                  },
                  "unit": {
                    "type": "string"
                  },
                  "substitution": {
                    "type": "string",
                    "description": "Alternative for dietary restrictions"
                  },
                  "allergens": {
                    "type": "array",
                    "items": {
                      "type": "string"
                    },
                    "description": "Any allergens present (e.g., 'gluten', 'dairy', 'nuts')"
                  }
                }
              }
            }
          }
        }
      },
      "servingsBase": {
        "type": "number",
        "description": "Number of servings this list is scaled for"
      },
      "pantryAssumptions": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "description": "Common ingredients assumed to be on hand (salt, pepper, oil, etc.)"
      }
    },
    "dependsOn": [
      "select-cuisine-and-dish"
    ]
  },
  {
    "id": "prepare-mise-en-place",
    "instructions": "Create a detailed mise en place guide for the selected dish. Organize all preparation tasks that should be completed before cooking begins — washing, chopping, measuring, marinating, pre-heating. Group tasks by timing: what can be done hours ahead, what should be done right before cooking. Include knife cuts, sizes, and any technique notes for each preparation step.",
    "outputSchema": {
      "advancePrep": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "task": {
              "type": "string"
            },
            "ingredient": {
              "type": "string"
            },
            "details": {
              "type": "string",
              "description": "Specific cut, size, or technique notes"
            },
            "timeAhead": {
              "type": "string",
              "description": "How far in advance this can be done"
            }
          }
        },
        "description": "Tasks that can be done hours or a day ahead"
      },
      "immediatePrep": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "task": {
              "type": "string"
            },
            "ingredient": {
              "type": "string"
            },
            "details": {
              "type": "string"
            }
          }
        },
        "description": "Tasks to do right before cooking"
      },
      "equipmentNeeded": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "description": "Tools and equipment to have ready"
      }
    },
    "dependsOn": [
      "gather-ingredients"
    ]
  },
  {
    "id": "cook-step-by-step",
    "instructions": "Generate the full cooking instructions for the dish. Load the relevant technique knowledge (sauté, grill, braise) to provide accurate method guidance. Each step should include precise timing, temperature, and sensory cues for doneness (visual, aroma, texture). Flag critical moments where timing or technique matters most. Include tips for common mistakes and how to recover from them.",
    "outputSchema": {
      "steps": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "stepNumber": {
              "type": "number"
            },
            "action": {
              "type": "string",
              "description": "What to do"
            },
            "technique": {
              "type": "string",
              "description": "Cooking technique used (e.g., 'sauté', 'simmer', 'fold')"
            },
            "duration": {
              "type": "string",
              "description": "Time for this step"
            },
            "temperature": {
              "type": "string",
              "description": "Heat level or specific temperature"
            },
            "donenessCue": {
              "type": "string",
              "description": "How to know this step is complete (visual, aroma, texture)"
            },
            "tip": {
              "type": "string",
              "description": "Common mistake or pro tip for this step"
            }
          }
        }
      },
      "totalActiveTime": {
        "type": "string",
        "description": "Total hands-on cooking time"
      },
      "totalPassiveTime": {
        "type": "string",
        "description": "Total resting, simmering, or baking time"
      }
    },
    "dependsOn": [
      "prepare-mise-en-place"
    ]
  },
  {
    "id": "analyze-nutrition",
    "instructions": "Analyze the nutritional content of the completed recipe. Use the estimateCalories function to calculate calorie totals from macronutrient estimates. Break down per-serving values for calories, protein, carbohydrates, fat, and fiber. Identify the primary nutrient sources from the ingredient list. Note any nutritional highlights or considerations relevant to the user's dietary restrictions.",
    "outputSchema": {
      "perServing": {
        "type": "object",
        "properties": {
          "calories": {
            "type": "number"
          },
          "protein": {
            "type": "string",
            "description": "Grams of protein"
          },
          "carbohydrates": {
            "type": "string",
            "description": "Grams of carbs"
          },
          "fat": {
            "type": "string",
            "description": "Grams of fat"
          },
          "fiber": {
            "type": "string",
            "description": "Grams of fiber"
          }
        }
      },
      "nutrientSources": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "nutrient": {
              "type": "string"
            },
            "primarySource": {
              "type": "string",
              "description": "Main ingredient providing this nutrient"
            }
          }
        }
      },
      "dietaryNotes": {
        "type": "array",
        "items": {
          "type": "string"
        },
        "description": "Highlights or considerations for specific dietary needs"
      }
    },
    "dependsOn": [
      "cook-step-by-step"
    ]
  }
])

